import{_ as o,o as t,c as s,ak as r,al as a}from"./chunks/framework.D7e0356g.js";const u=JSON.parse('{"title":"CI/CD and workflow behavior","description":"","frontmatter":{},"headers":[],"relativePath":"ci-cd.md","filePath":"ci-cd.md"}'),i={name:"ci-cd.md"};function n(l,e,c,d,p,h){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="ci-cd-and-workflow-behavior" tabindex="-1">CI/CD and workflow behavior <a class="header-anchor" href="#ci-cd-and-workflow-behavior" aria-label="Permalink to “CI/CD and workflow behavior”">​</a></h1><p>All workflows live under <a href="https://github.com/bcgov/bcew-monorepo/tree/main/.github/workflows" target="_blank" rel="noreferrer"><code>.github/workflows/</code></a>. This page summarizes behavior; inline workflow comments and the <a href="https://github.com/bcgov/bcew-monorepo/blob/main/.github/workflows/README.md" target="_blank" rel="noreferrer">workflows README</a> are authoritative for details.</p><h2 id="pull-requests-pr-yml" tabindex="-1">Pull requests (<code>pr.yml</code>) <a class="header-anchor" href="#pull-requests-pr-yml" aria-label="Permalink to “Pull requests (pr.yml)”">​</a></h2><p><strong>Triggers:</strong> Every <code>pull_request</code> event.</p><p><strong>Concurrency:</strong> One run per PR; newer commits cancel in-progress runs for that PR.</p><p><strong>Typical steps:</strong></p><ol><li><strong>Labeler</strong> — Applies labels from <code>.github/labeler.yml</code> based on changed paths.</li><li><strong>Install</strong> — pnpm and Node (see workflow for versions), <code>pnpm install</code>, root <code>composer install</code>.</li><li><strong>Lint</strong> — Full monorepo lint: PHP, JS, CSS, Markdown, <code>package.json</code>.</li><li><strong>Build</strong> — <code>npx nx affected --base=&quot;origin/&lt;base_branch&gt;&quot; -t build</code> so only <strong>affected</strong> projects build.</li><li><strong>Tests</strong>: <ol><li><strong>Integration</strong> — PHP WordPress integration tests using wp-env.</li><li><strong>e2e</strong> — e2e tests using Playwright and wp-env.</li><li><strong>Screenshot</strong> — Visual regression tests using Playwright and wp-env. Compares screenshots <ul><li><strong>Note</strong>: If a screenshot test fails in the CI/CD, check the artifact it uploads during the <code>actions/upload-artifact</code> step. It will contain a zip of the diff between the expected screenshots and the ones it produced. Usually the fix for this will require running <code>npx nx test-screenshot-generate</code> locally to generate new screenshots.</li></ul></li></ol></li><li><strong>Artifacts</strong> — Playwright report uploaded on completion (unless cancelled).</li></ol><h3 id="how-affected-is-chosen" tabindex="-1">How “affected” is chosen <a class="header-anchor" href="#how-affected-is-chosen" aria-label="Permalink to “How “affected” is chosen”">​</a></h3><p>The PR workflow compares the PR head to <code>origin/&lt;github.base_ref&gt;</code> (the target branch, usually <code>main</code>). Any project touched or implied by the Nx graph runs the expensive targets.</p><p>Reusable workflow <code>detect-affected-projects.yml</code> exists for <strong>callable</strong> workflows; it computes affected <strong>app</strong> projects for a given base/head. Keep it in mind if you add new workflows that need the same logic.</p><h2 id="merges-to-main" tabindex="-1">Merges to <code>main</code> <a class="header-anchor" href="#merges-to-main" aria-label="Permalink to “Merges to main”">​</a></h2><ul><li><strong>Docs:</strong> Pushes to <code>main</code> that touch <code>docs/**</code>, package <code>docs/**</code>, sync script, or docs workflow deploy the VitePress site via <code>deploy-docs.yml</code> (see <a href="./documentation-site">Documentation site</a>).</li><li><strong>Releases:</strong> Merging code does <strong>not</strong> by itself publish plugin/theme zip artifacts. Publishing is <strong>tag-driven</strong> (<code>tag.yml</code>).</li></ul><h2 id="tags-tag-yml" tabindex="-1">Tags (<code>tag.yml</code>) <a class="header-anchor" href="#tags-tag-yml" aria-label="Permalink to “Tags (tag.yml)”">​</a></h2><p>On the GitHub repository, navigate to Actions &gt; Release Subproject and Update packages.json &gt; Run workflow. You should see the following options: <img src="'+a+'" alt="Release workflow options"></p><p>Manual workflow used to create releases, given the following inputs:</p><ul><li>Branch: Dropdown providing all branches from which this workflow can be run. Sometimes you may want to create a release off of a non-main branch if something must be tested remotely before it can be merged. In these cases, it should always be a prerelease. Most of the time releases will be created off the main branch.</li><li>Project name: Dropdown providing the names of all monorepo projects.</li><li>Version: Text input for the version to be released, eg. <code>1.0.1-alpha.1</code>.</li><li>Is prerelease: Boolean input determining if it&#39;s a prerelease. A prerelease version has a postfix like <code>alpha.1</code>.</li></ul><p>What this workflow does:</p><ol><li>Updates versions in source, eg. updates <code>style.css</code> or <code>{plugin name}.php</code> version fields.</li><li>Generates release notes describing all pull requests merged into the release.</li><li>Creates a tag using the project name and version provided as inputs, eg. <code>bcew-project/v1.0.1-alpha.1</code>.</li><li>Builds the project and creates a zip of the result, <code>dist.zip</code>.</li><li>Creates a GitHub Release and attaches <code>dist.zip</code> as an asset. Sets to prerelease if &quot;is prerelease&quot; input is true.</li><li>Updates <code>packages.json</code> for the Composer repository on GitHub Pages and deploys it.</li></ol>',18)])])}const f=o(i,[["render",n]]);export{u as __pageData,f as default};
